    /// <summary>
    /// When verify passes (green), the stage-9 agent must receive the driver's
    /// captured test output and the test command so it can produce an accurate
    /// summary without re-running the suite itself.
    /// </summary>
    [Fact]
    public async Task RunTaskAsync_VerifyGreen_Stage9AgentReceivesCapturedTestOutput()
    {
        using var repo = TestRepository.Create();
        repo.WriteConfig("dotnet test", [], baselineVerify: false, maxVerifyLoops: 1);
        repo.WriteTask("stage9-green-output", "# Stage 9 receives green output\n");
        var runner = new CapturingSubagentRunner();
        runner.SeedHappyPath("src/app.cs", "tests/app.tests.cs");
        var tests = new ScriptedTestRunner(
            new TestRunResult(1, "red"),         // stage 5 author gate
            new TestRunResult(0, "All 42 tests passed!")); // stage 9 verify — green
        var driver = new RelayDriver(
            RelayDriverDependencies.ForTests(runner, tests, new InMemoryRelayEventSink()),
            RelayDriverOptions.NoGitCommit);

        var outcome = await driver.RunTaskAsync(repo.Root, "stage9-green-output");

        Assert.Equal(RelayTaskOutcomeStatus.Committed, outcome.Status);
        var stage9Invocation = runner.Invocations.SingleOrDefault(i => i.Stage.Number == 9);
        Assert.NotNull(stage9Invocation);
        // The agent must receive the driver's captured test output — it must NOT be null.
        Assert.NotNull(stage9Invocation!.LastTestOutput);
        Assert.Contains("All 42 tests passed!", stage9Invocation.LastTestOutput, StringComparison.Ordinal);
        // The agent must also receive the test command itself.
        Assert.NotNull(stage9Invocation.TestCommand);
        Assert.Equal("dotnet test", stage9Invocation.TestCommand);
    }

    /// <summary>
    /// When verify fails (red → fix-verify loop), the stage-9 agent must still
    /// receive the driver's captured failing test output and the test command.
    /// The agent must summarize from the driver-provided results, not re-run.
    /// </summary>
    [Fact]
    public async Task RunTaskAsync_VerifyRed_Stage9AgentReceivesFailingTestOutput()
    {
        using var repo = TestRepository.Create();
        repo.WriteConfig("dotnet test", [], baselineVerify: false, maxVerifyLoops: 2);
        repo.WriteTask("stage9-fail-output", "# Stage 9 receives failing output\n");
        var runner = new CapturingSubagentRunner();
        runner.SeedHappyPath("src/app.cs", "tests/app.tests.cs");
        var tests = new ScriptedTestRunner(
            new TestRunResult(1, "red"),                    // stage 5 author gate
            new TestRunResult(1, "FAIL: TestDeepCheck"),     // stage 9 verify — first run fails
            new TestRunResult(1, "FAIL: TestDeepCheck"),     // stage 9 verify — retry also fails
            new TestRunResult(1, "FAIL: TestDeepCheck"),     // fix-verify attempt 1 gate — red
            new TestRunResult(0, "All green!"));             // fix-verify attempt 1 retry — green
        var driver = new RelayDriver(
            RelayDriverDependencies.ForTests(runner, tests, new InMemoryRelayEventSink()),
            RelayDriverOptions.NoGitCommit);

        var outcome = await driver.RunTaskAsync(repo.Root, "stage9-fail-output");

        Assert.Equal(RelayTaskOutcomeStatus.Committed, outcome.Status);
        var stage9Invocation = runner.Invocations.SingleOrDefault(i => i.Stage.Number == 9);
        Assert.NotNull(stage9Invocation);
        Assert.NotNull(stage9Invocation!.LastTestOutput);
        Assert.Contains("FAIL: TestDeepCheck", stage9Invocation.LastTestOutput, StringComparison.Ordinal);
        Assert.NotNull(stage9Invocation.TestCommand);
        Assert.Equal("dotnet test", stage9Invocation.TestCommand);
    }
}

